1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (alive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (alive && neighbors === 2);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const live = new Set(cells.map(keyOf));
16	  const candidates = cells.flatMap(([x, y]) =>
17	    NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
18	  );
19	
20	  const counts = new Map<string, number>();
21	  for (const c of candidates) {
22	    const k = keyOf(c);
23	    counts.set(k, (counts.get(k) ?? 0) + 1);
24	  }
25	
26	  const unique = new Map<string, Cell>(candidates.map((c) => [keyOf(c), c]));
27	  return [...unique].filter(([k]) => survives(live.has(k), counts.get(k)!))
28	                    .map(([, c]) => c);
29	}
