1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should transform a vertical blinker into a horizontal blinker", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
28	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
29	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    const result = nextGeneration(input);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
35	    // Center cell (1,1) has 4 live neighbors -> dies
36	    const input: [number, number][] = [
37	      [0, 0], [1, 0], [2, 0],
38	      [1, 1],
39	      [0, 2], [1, 2], [2, 2],
40	    ];
41	    const result = nextGeneration(input);
42	    const hasCenter = result.some(([x, y]) => x === 1 && y === 1);
43	    expect(hasCenter).toBe(false);
44	  });
45	  it("should handle negative coordinates correctly", () => {
46	    const vertical: [number, number][] = [[-1, -1], [-1, 0], [-1, 1]];
47	    const expected: [number, number][] = [[-2, 0], [-1, 0], [0, 0]];
48	    const result = nextGeneration(vertical);
49	    expect(result).toHaveLength(3);
50	    expect(result).toEqual(expect.arrayContaining(expected));
51	  });
52	});
