export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(keyOf));
  const candidates = cells.flatMap(([x, y]) =>
    NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
  );

  const counts = new Map<string, number>();
  for (const c of candidates) {
    const k = keyOf(c);
    counts.set(k, (counts.get(k) ?? 0) + 1);
  }

  const unique = new Map<string, Cell>(candidates.map((c) => [keyOf(c), c]));
  return [...unique].filter(([k]) => survives(live.has(k), counts.get(k)!))
                    .map(([, c]) => c);
}

