const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(keyOf));
  const neighborCounts = cells
    .flatMap(neighborsOf)
    .reduce(
      (acc, cell) => acc.set(keyOf(cell), [cell, (acc.get(keyOf(cell))?.[1] ?? 0) + 1]),
      new Map<string, [Cell, number]>()
    );

  return [...neighborCounts.values()]
    .filter(([cell, count]) => survives(live.has(keyOf(cell)), count))
    .map(([cell]) => cell);
}

